'use client'

import React, { createContext, useContext, useMemo } from 'react'
import type { TokenConfig, Palette } from './types'
import { resolveTokens, resolveTokensToStyle } from './resolve'

interface TokenContextValue {
  config: TokenConfig
  palette: Palette
  paletteName: string
  theme: 'light' | 'dark'
}

const TokenContext = createContext<TokenContextValue | null>(null)

export function TokenProvider({
  config,
  paletteName,
  children,
}: {
  config: TokenConfig
  paletteName?: string
  children: React.ReactNode
}) {
  const name = paletteName || config.defaultPalette
  const palette: Palette = config.palettes[name] || config.palettes[config.defaultPalette]
  const style = useMemo(() => resolveTokensToStyle(config, name), [config, name])

  return (
    <TokenContext.Provider value={{ config, palette, paletteName: name, theme: config.theme }}>
      <div id="paragu-ai-tokens" style={style as React.CSSProperties}>
        {children}
      </div>
    </TokenContext.Provider>
  )
}

export function useTokens(): TokenContextValue {
  const ctx = useContext(TokenContext)
  if (!ctx) throw new Error('useTokens() must be used inside <TokenProvider>')
  return ctx
}

export function usePalette(): Palette {
  return useTokens().palette
}
EOF

