'use client'

import React from 'react'

type ButtonVariant = 'primary' | 'secondary' | 'outline' | 'ghost' | 'link'
type ButtonSize = 'sm' | 'md' | 'lg'

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: ButtonVariant
  size?: ButtonSize
  loading?: boolean
  href?: string
  children: React.ReactNode
}

const variantStyles: Record<ButtonVariant, React.CSSProperties> = {
  primary: { backgroundColor: 'var(--primary)', color: 'var(--primary-foreground)', border: 'none' },
  secondary: { backgroundColor: 'var(--secondary)', color: 'var(--secondary-foreground)', border: 'none' },
  outline: { backgroundColor: 'transparent', color: 'var(--primary)', border: '2px solid var(--primary)' },
  ghost: { backgroundColor: 'transparent', color: 'var(--text)', border: 'none' },
  link: { backgroundColor: 'transparent', color: 'var(--primary)', border: 'none', textDecoration: 'underline' },
}

const sizeStyles: Record<ButtonSize, React.CSSProperties> = {
  sm: { padding: '6px 12px', fontSize: '0.875rem', borderRadius: '6px' },
  md: { padding: '10px 20px', fontSize: '1rem', borderRadius: '8px' },
  lg: { padding: '14px 28px', fontSize: '1.125rem', borderRadius: '10px' },
}

export function Button({
  variant = 'primary',
  size = 'md',
  loading = false,
  href,
  children,
  style,
  disabled,
  ...props
}: ButtonProps) {
  const baseStyle: React.CSSProperties = {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '8px',
    fontWeight: 600,
    cursor: disabled || loading ? 'not-allowed' : 'pointer',
    opacity: disabled || loading ? 0.6 : 1,
    transition: 'all 0.15s ease',
    fontFamily: 'var(--font-body, inherit)',
    ...variantStyles[variant],
    ...sizeStyles[size],
    ...style,
  }

  const content = loading ? (
    <>
      <span style={{ width: 16, height: 16, border: '2px solid currentColor', borderTopColor: 'transparent', borderRadius: '50%', animation: 'pa-spin 0.6s linear infinite', display: 'inline-block' }} />
      {children}
    </>
  ) : children

  if (href && !disabled) {
    return <a href={href} style={{ ...baseStyle, textDecoration: 'none' } as React.CSSProperties}>{content}</a>
  }

  return <button {...props} disabled={disabled || loading} style={baseStyle}>{content}</button>
}
EOF

