'use client'

import React, { createContext, useContext, useState, useCallback } from 'react'

interface Toast {
  id: string
  message: string
  type: 'success' | 'error' | 'info' | 'warning'
}

interface ToastContextValue {
  showToast: (message: string, type?: Toast['type']) => void
}

const ToastContext = createContext<ToastContextValue | null>(null)

const typeStyles: Record<Toast['type'], React.CSSProperties> = {
  success: { backgroundColor: 'var(--success, #16a34a)', color: 'white' },
  error: { backgroundColor: 'var(--error, #dc2626)', color: 'white' },
  info: { backgroundColor: 'var(--primary)', color: 'var(--primary-foreground)' },
  warning: { backgroundColor: 'var(--warning, #f59e0b)', color: 'white' },
}

export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([])

  const showToast = useCallback((message: string, type: Toast['type'] = 'info') => {
    const id = Date.now().toString()
    setToasts(prev => [...prev, { id, message, type }])
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id))
    }, 4000)
  }, [])

  const remove = (id: string) => setToasts(prev => prev.filter(t => t.id !== id))

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      <div style={{
        position: 'fixed',
        top: 16,
        right: 16,
        display: 'flex',
        flexDirection: 'column',
        gap: 8,
        zIndex: 99999,
      }}>
        {toasts.map(t => (
          <div
            key={t.id}
            onClick={() => remove(t.id)}
            role="alert"
            style={{
              padding: '12px 20px',
              borderRadius: 8,
              fontWeight: 500,
              fontSize: '0.875rem',
              boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
              cursor: 'pointer',
              animation: 'pa-slide-in 0.3s ease-out',
              ...typeStyles[t.type],
            }}
          >
            {t.message}
          </div>
        ))}
      </div>
      <style>{`
        @keyframes pa-slide-in {
          from { transform: translateX(100%); opacity: 0; }
          to { transform: translateX(0); opacity: 1; }
        }
      `}</style>
    </ToastContext.Provider>
  )
}

export function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext)
  if (!ctx) throw new Error('useToast() must be used inside <ToastProvider>')
  return ctx
}
